package main

import (
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"errors"
	"fmt"
	"io"
	"log"
	"os"
)

// VULNERABLE: Using math/rand for cryptographic operations
func generateWeakKey() (*rsa.PrivateKey, error) {
	// DO NOT USE - This is vulnerable!
	// import "math/rand"
	// rand.Seed(time.Now().UnixNano()) // Predictable!
	// This would allow attackers to predict keys
	return nil, errors.New("weak key generation - DO NOT USE")
}

// SECURE: Generate RSA key pair with crypto/rand
func GenerateRSAKeyPair(bits int) (*rsa.PrivateKey, error) {
	if bits < 2048 {
		return nil, fmt.Errorf("key size must be at least 2048 bits, got %d", bits)
	}

	// Use crypto/rand.Reader which provides cryptographically secure random numbers
	privateKey, err := rsa.GenerateKey(rand.Reader, bits)
	if err != nil {
		return nil, fmt.Errorf("failed to generate RSA key: %w", err)
	}

	// Validate key generation
	err = privateKey.Validate()
	if err != nil {
		return nil, fmt.Errorf("key validation failed: %w", err)
	}

	return privateKey, nil
}

// Generate and save RSA key pair to PEM files
func GenerateAndSaveKeyPair(privateKeyPath, publicKeyPath string, bits int) error {
	// Generate key pair
	privateKey, err := GenerateRSAKeyPair(bits)
	if err != nil {
		return err
	}

	// Save private key
	privateKeyFile, err := os.OpenFile(privateKeyPath, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, 0600)
	if err != nil {
		return fmt.Errorf("failed to create private key file: %w", err)
	}
	defer privateKeyFile.Close()

	privateKeyBytes := x509.MarshalPKCS1PrivateKey(privateKey)
	privateKeyPEM := &pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: privateKeyBytes,
	}

	err = pem.Encode(privateKeyFile, privateKeyPEM)
	if err != nil {
		return fmt.Errorf("failed to encode private key: %w", err)
	}

	// Save public key
	publicKeyFile, err := os.OpenFile(publicKeyPath, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, 0644)
	if err != nil {
		return fmt.Errorf("failed to create public key file: %w", err)
	}
	defer publicKeyFile.Close()

	publicKeyBytes, err := x509.MarshalPKIXPublicKey(&privateKey.PublicKey)
	if err != nil {
		return fmt.Errorf("failed to marshal public key: %w", err)
	}

	publicKeyPEM := &pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: publicKeyBytes,
	}

	err = pem.Encode(publicKeyFile, publicKeyPEM)
	if err != nil {
		return fmt.Errorf("failed to encode public key: %w", err)
	}

	return nil
}

// Generate random bytes for encryption keys, IVs, nonces
func GenerateRandomBytes(n int) ([]byte, error) {
	b := make([]byte, n)
	_, err := rand.Read(b)
	if err != nil {
		return nil, fmt.Errorf("failed to generate random bytes: %w", err)
	}
	return b, nil
}

// Generate AES-256 key (32 bytes = 256 bits)
func GenerateAESKey() ([]byte, error) {
	return GenerateRandomBytes(32)
}

// Generate secure random token
func GenerateSecureToken(length int) (string, error) {
	b := make([]byte, length)
	_, err := rand.Read(b)
	if err != nil {
		return "", err
	}
	return fmt.Sprintf("%x", b), nil
}

// Check entropy availability (Unix/Linux)
func CheckEntropyAvailable() (int, error) {
	// On Linux, check available entropy in bytes
	data, err := os.ReadFile("/proc/sys/kernel/random/entropy_avail")
	if err != nil {
		return 0, err
	}
	var entropy int
	_, err = fmt.Sscanf(string(data), "%d", &entropy)
	return entropy, err
}

// Test crypto/rand is properly seeded
func TestRandomness() error {
	// Generate test sample
	testBytes := make([]byte, 1024)
	n, err := rand.Read(testBytes)
	if err != nil {
		return fmt.Errorf("rand.Read failed: %w", err)
	}
	if n != len(testBytes) {
		return fmt.Errorf("rand.Read returned %d bytes, expected %d", n, len(testBytes))
	}

	// Basic entropy check - all zeros would indicate problem
	zeroCount := 0
	for _, b := range testBytes {
		if b == 0 {
			zeroCount++
		}
	}
	if zeroCount > 900 { // More than ~88% zeros is suspicious
		return fmt.Errorf("insufficient randomness: %d/%d bytes are zero", zeroCount, len(testBytes))
	}

	return nil
}

func main() {
	// Check system entropy
	if entropy, err := CheckEntropyAvailable(); err == nil {
		log.Printf("Available entropy: %d bits", entropy)
		if entropy < 128 {
			log.Printf("WARNING: Low entropy (%d bits). Key generation may block.", entropy)
		}
	}

	// Test randomness
	if err := TestRandomness(); err != nil {
		log.Fatalf("Randomness test failed: %v", err)
	}

	// Generate RSA 4096-bit key pair
	log.Println("Generating 4096-bit RSA key pair...")
	err := GenerateAndSaveKeyPair("private.pem", "public.pem", 4096)
	if err != nil {
		log.Fatalf("Key generation failed: %v", err)
	}
	log.Println("Key pair generated successfully")

	// Generate AES-256 key
	aesKey, err := GenerateAESKey()
	if err != nil {
		log.Fatalf("AES key generation failed: %v", err)
	}
	log.Printf("Generated AES-256 key: %x", aesKey)

	// Generate secure random token
	token, err := GenerateSecureToken(32)
	if err != nil {
		log.Fatalf("Token generation failed: %v", err)
	}
	log.Printf("Generated secure token: %s", token)
}

import java.security.*;
import javax.crypto.*;
import javax.crypto.spec.*;
import java.security.spec.*;
import java.util.Base64;
import java.io.*;
import java.nio.file.*;

public class SecureKeyGenerator {

    // VULNERABLE - DO NOT USE
    public static byte[] generateWeakKey() {
        // This is INSECURE and predictable!
        java.util.Random weakRandom = new java.util.Random();
        byte[] key = new byte[32];
        weakRandom.nextBytes(key);
        return key; // DO NOT USE!
    }

    // SECURE: Initialize SecureRandom with strong algorithm
    private static SecureRandom getSecureRandom() throws NoSuchAlgorithmException {
        // Try NativePRNGNonBlocking first (preferred on Unix/Linux)
        try {
            return SecureRandom.getInstance("NativePRNGNonBlocking");
        } catch (NoSuchAlgorithmException e) {
            // Fallback to default strong algorithm
            return SecureRandom.getInstanceStrong();
        }
    }

    // Generate RSA key pair with minimum 2048 bits
    public static KeyPair generateRSAKeyPair(int keySize) throws NoSuchAlgorithmException {
        if (keySize < 2048) {
            throw new IllegalArgumentException(
                "RSA key size must be at least 2048 bits, got: " + keySize
            );
        }

        KeyPairGenerator keyPairGen = KeyPairGenerator.getInstance("RSA");

        // Use SecureRandom for key generation
        SecureRandom secureRandom = getSecureRandom();
        keyPairGen.initialize(keySize, secureRandom);

        return keyPairGen.generateKeyPair();
    }

    // Generate AES-256 encryption key
    public static SecretKey generateAESKey(int keySize) throws NoSuchAlgorithmException {
        if (keySize != 128 && keySize != 192 && keySize != 256) {
            throw new IllegalArgumentException(
                "AES key size must be 128, 192, or 256 bits"
            );
        }

        KeyGenerator keyGen = KeyGenerator.getInstance("AES");
        SecureRandom secureRandom = getSecureRandom();
        keyGen.init(keySize, secureRandom);

        return keyGen.generateKey();
    }

    // Generate ECDSA key pair (Elliptic Curve)
    public static KeyPair generateECKeyPair(String curveName) 
            throws NoSuchAlgorithmException, InvalidAlgorithmParameterException {
        // Recommended curves: secp256r1, secp384r1, secp521r1
        KeyPairGenerator keyPairGen = KeyPairGenerator.getInstance("EC");

        ECGenParameterSpec ecSpec = new ECGenParameterSpec(curveName);
        SecureRandom secureRandom = getSecureRandom();

        keyPairGen.initialize(ecSpec, secureRandom);
        return keyPairGen.generateKeyPair();
    }

    // Generate cryptographically secure random bytes
    public static byte[] generateRandomBytes(int length) throws NoSuchAlgorithmException {
        SecureRandom secureRandom = getSecureRandom();
        byte[] randomBytes = new byte[length];
        secureRandom.nextBytes(randomBytes);
        return randomBytes;
    }

    // Generate secure random token
    public static String generateSecureToken(int numBytes) throws NoSuchAlgorithmException {
        byte[] randomBytes = generateRandomBytes(numBytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(randomBytes);
    }

    // Save private key to file with proper permissions
    public static void savePrivateKey(PrivateKey privateKey, String filename) 
            throws IOException {
        byte[] keyBytes = privateKey.getEncoded();

        // Save with restricted permissions (owner read/write only)
        Path keyPath = Paths.get(filename);
        Files.write(keyPath, keyBytes);

        // Set file permissions to 600 (owner read/write only)
        try {
            Set<PosixFilePermission> perms = new HashSet<>();
            perms.add(PosixFilePermission.OWNER_READ);
            perms.add(PosixFilePermission.OWNER_WRITE);
            Files.setPosixFilePermissions(keyPath, perms);
        } catch (UnsupportedOperationException e) {
            // Windows doesn't support POSIX permissions
            System.out.println("POSIX permissions not supported on this platform");
        }
    }

    // Save public key to file
    public static void savePublicKey(PublicKey publicKey, String filename) 
            throws IOException {
        byte[] keyBytes = publicKey.getEncoded();
        Files.write(Paths.get(filename), keyBytes);
    }

    // Check SecureRandom algorithm being used
    public static void printSecureRandomInfo() throws NoSuchAlgorithmException {
        SecureRandom sr = getSecureRandom();
        System.out.println("SecureRandom Algorithm: " + sr.getAlgorithm());
        System.out.println("SecureRandom Provider: " + sr.getProvider().getName());
    }

    // Test entropy availability (Linux/Unix)
    public static int checkEntropyAvailable() {
        try {
            String entropy = new String(
                Files.readAllBytes(Paths.get("/proc/sys/kernel/random/entropy_avail"))
            ).trim();
            return Integer.parseInt(entropy);
        } catch (Exception e) {
            return -1; // Not available on this platform
        }
    }

    public static void main(String[] args) {
        try {
            // Print SecureRandom configuration
            printSecureRandomInfo();

            // Check entropy (Unix/Linux only)
            int entropy = checkEntropyAvailable();
            if (entropy >= 0) {
                System.out.println("Available entropy: " + entropy + " bits");
                if (entropy < 128) {
                    System.out.println("WARNING: Low entropy. Key generation may be slow.");
                }
            }

            // Generate RSA 4096-bit key pair
            System.out.println("\nGenerating RSA 4096-bit key pair...");
            KeyPair rsaKeyPair = generateRSAKeyPair(4096);
            savePrivateKey(rsaKeyPair.getPrivate(), "rsa_private.key");
            savePublicKey(rsaKeyPair.getPublic(), "rsa_public.key");
            System.out.println("RSA key pair generated and saved");

            // Generate AES-256 key
            System.out.println("\nGenerating AES-256 key...");
            SecretKey aesKey = generateAESKey(256);
            String aesKeyHex = Base64.getEncoder().encodeToString(aesKey.getEncoded());
            System.out.println("AES-256 Key: " + aesKeyHex);

            // Generate ECDSA key pair
            System.out.println("\nGenerating ECDSA key pair (secp256r1)...");
            KeyPair ecKeyPair = generateECKeyPair("secp256r1");
            System.out.println("ECDSA key pair generated");

            // Generate secure token
            String token = generateSecureToken(32);
            System.out.println("\nSecure Token: " + token);

        } catch (Exception e) {
            System.err.println("Error: " + e.getMessage());
            e.printStackTrace();
        }
    }
}
